<div class="grid grid-3"><div class="card"><h3>Add Branch</h3><form method="post" action="<?=url('/organization/branch')?>"><?=csrf_field()?><label>Code</label><input name="code" required><label>Name</label><input name="name" required><br><br><button class="btn btn-primary">Save</button></form></div><div class="card"><h3>Add Department</h3><form method="post" action="<?=url('/organization/department')?>"><?=csrf_field()?><label>Code</label><input name="code" required><label>Name</label><input name="name" required><input type="hidden" name="parent_id"><br><br><button class="btn btn-primary">Save</button></form></div><div class="card"><h3>Add Position</h3><form method="post" action="<?=url('/organization/position')?>"><?=csrf_field()?><label>Department</label><select name="department_id"><?php foreach($departments as $d):?><option value="<?=e($d['id'])?>"><?=e($d['name'])?></option><?php endforeach;?></select><label>Name</label><input name="name" required><label>Grade</label><input name="grade"><br><br><button class="btn btn-primary">Save</button></form></div></div><br><div class="grid grid-3"><div class="card"><h3>Branches</h3><table class="table"><?php foreach($branches as $b):?><tr><td><?=e($b['code'])?></td><td><?=e($b['name'])?></td></tr><?php endforeach;?></table></div><div class="card"><h3>Departments</h3><table class="table"><?php foreach($departments as $d):?><tr><td><?=e($d['code'])?></td><td><?=e($d['name'])?></td></tr><?php endforeach;?></table></div><div class="card"><h3>Positions</h3><table class="table"><?php foreach($positions as $p):?><tr><td><?=e($p['name'])?></td><td><?=e($p['department_name'])?></td></tr><?php endforeach;?></table></div></div>
